import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"ADR-040 — ISS Explorer asset pipeline and nav placement","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-040.md","filePath":"adr/ADR-040.md"}'),s={name:"adr/ADR-040.md"};function n(i,e,d,l,c,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-040-—-iss-explorer-asset-pipeline-and-nav-placement" tabindex="-1">ADR-040 — ISS Explorer asset pipeline and nav placement <a class="header-anchor" href="#adr-040-—-iss-explorer-asset-pipeline-and-nav-placement" aria-label="Permalink to &quot;ADR-040 — ISS Explorer asset pipeline and nav placement&quot;">​</a></h1><blockquote><p>Status · Accepted<br> Date · 2026-05-05<br> Closes · RFC-013 (with ADR-041, ADR-042)<br> TA anchor · §components / primary-route-pages<br> Related · PRD-010, ADR-016 (build-time assets), ADR-017 (i18n)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>PRD-010 / GitHub #41 introduce <code>/iss</code>: a rotatable ISS with per-module panels. RFC-013 asked where the mesh comes from, how heavy it may be, Earth backdrop, and nav order.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="model-source-rfc-oq-1-—-option-a-refined" tabindex="-1">Model source (RFC OQ-1 — Option A refined) <a class="header-anchor" href="#model-source-rfc-oq-1-—-option-a-refined" aria-label="Permalink to &quot;Model source (RFC OQ-1 — Option A refined)&quot;">​</a></h3><p><strong>V1 ships a code-built diagrammatic ISS</strong> in <a href="../../src/lib/iss-proxy-model.ts"><code>src/lib/iss-proxy-model.ts</code></a>: Three.js box primitives + truss/array meshes assembled at runtime so each canonical module id from <a href="../../static/data/iss-modules.json"><code>iss-modules.json</code></a> maps to a named pickable mesh (<code>userData.moduleId</code>). <strong>No Node-side GLTF export</strong> — Three.js <code>GLTFExporter</code> depends on browser <code>FileReader</code>, so CI cannot emit a proxy GLB without extra tooling.</p><p><strong>Rationale:</strong> NASA Science publishes low-detail ISS GLB references suitable for a future Blender-split swap-in; until then the proxy satisfies picking, attribution panels, and performance teaching goals while staying MIT-licensed and negligible in download weight. <code>static/models/iss/CREDITS.md</code> records NASA reference links.</p><p><strong>Budget:</strong> Proxy stays <strong>≪ 50k tris</strong> (actually low thousands). A future NASA-derived GLB must stay within PRD <strong>~50k tris</strong> and <strong>&lt; 4 MB</strong> gzipped when upgraded.</p><h3 id="earth-limb-backdrop-rfc-oq-4-—-option-b" tabindex="-1">Earth limb backdrop (RFC OQ-4 — Option B) <a class="header-anchor" href="#earth-limb-backdrop-rfc-oq-4-—-option-b" aria-label="Permalink to &quot;Earth limb backdrop (RFC OQ-4 — Option B)&quot;">​</a></h3><p>Static <strong>Earth limb</strong> behind the station using existing texture <a href="../../static/textures/2k_earth_daymap.jpg"><code>static/textures/2k_earth_daymap.jpg</code></a> (same asset as <code>/earth</code> + <code>/explore</code>): large textured sphere, no animated rotation in V1.</p><h3 id="nav-order-rfc-oq-7" tabindex="-1">Nav order (RFC OQ-7) <a class="header-anchor" href="#nav-order-rfc-oq-7" aria-label="Permalink to &quot;Nav order (RFC OQ-7)&quot;">​</a></h3><p>Insert <strong>ISS</strong> after <strong>EARTH</strong>:</p><p><code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → ISS → MOON → MARS</code></p><h3 id="build-hook" tabindex="-1">Build hook <a class="header-anchor" href="#build-hook" aria-label="Permalink to &quot;Build hook&quot;">​</a></h3><p><code>npm run build</code> <strong>does not</strong> invoke Blender or mesh exporters. Adjust layout in <code>iss-proxy-model.ts</code> when module positions change.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Predictable CI; no multi-hundred-MB NASA checkout; clear path to replace GLB later.</p><p><strong>Negative:</strong> V1 silhouette is <strong>diagrammatic</strong>, not photoreal — acceptable for interaction proof; PRD “recognisable ISS” is partially met via layout and labelling, not film-grade mesh.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Loader: <code>GLTFLoader</code> from <code>three/examples/jsm</code> (Three r128).</li><li>Attribution: <code>static/models/iss/CREDITS.md</code>.</li></ul>',21)])])}const u=o(s,[["render",n]]);export{m as __pageData,u as default};
